import { createAgent, type FlueContext } from '@flue/runtime'
import * as v from 'valibot'
import { fetchPr } from '../tools/fetch-pr.ts'

const reviewer = createAgent(() => ({
  model: 'anthropic/claude-haiku-4-5',
  instructions: 'Fetch the PR and review it. Comment only on the diff, grouped by file.',
  tools: [fetchPr],
}))

const Review = v.object({
  summary: v.string(),
  recommendation: v.picklist(['approve', 'request_changes', 'comment']),
  comments: v.array(v.object({
    file: v.string(),
    severity: v.picklist(['bug', 'security', 'style', 'nit']),
    comment: v.string(),
  })),
})

export async function run({
  init,
  payload,
}: FlueContext<{ owner: string; repo: string; pullNumber: number }>) {
  const harness = await init(reviewer)
  const session = await harness.session()

  const response = await session.prompt(
    `Review pull request ${payload.owner}/${payload.repo}#${payload.pullNumber}.`,
    { result: Review }
  )

  return response.data
}

import { defineTool } from '@flue/runtime'
import * as v from 'valibot'

const GITHUB_API = 'https://api.github.com'

const headers = () => ({
  Accept: 'application/vnd.github+json',
  Authorization: `Bearer ${process.env.GITHUB_TOKEN ?? ''}`,
  'X-GitHub-Api-Version': '2022-11-28',
})

export const fetchPr = defineTool({
  name: 'fetch_pr',
  description:
    'Fetches a GitHub pull request — its metadata and the list of changed files with patches.',
  parameters: v.object({
    owner: v.string(),
    repo: v.string(),
    pullNumber: v.number(),
  }),
  execute: async ({ owner, repo, pullNumber }) => {
    const base = `${GITHUB_API}/repos/${owner}/${repo}/pulls/${pullNumber}`
    const [pr, files] = await Promise.all([
      fetch(base, { headers: headers() }).then((r) => r.json()),
      fetch(`${base}/files?per_page=100`, { headers: headers() }).then((r) =>
        r.json()
      ),
    ])
    return JSON.stringify({ pr, files }, null, 2)
  },
})
